code = """import json
import pandas as pd

# load the review results from storage variable
reviews = pd.DataFrame(var_call_69JP3OxS6mYVvgHvafjXvDlh)
# normalize types
if not reviews.empty:
    reviews['avg_rating'] = pd.to_numeric(reviews['avg_rating'], errors='coerce')
    reviews['n_reviews'] = pd.to_numeric(reviews['n_reviews'], errors='coerce')
else:
    reviews['avg_rating'] = pd.Series(dtype=float)
    reviews['n_reviews'] = pd.Series(dtype=int)

# derive book_id by replacing purchaseid_ with bookid_
reviews['book_id'] = reviews['purchase_id'].str.replace('purchaseid_', 'bookid_')

# load the full books_info result from the JSON file path
books_json_path = var_call_tukUcQNpcrHR6Eh0SyTafPjp
with open(books_json_path, 'r', encoding='utf-8') as f:
    books = json.load(f)

books_df = pd.DataFrame(books)

# Ensure book_id column exists
if 'book_id' not in books_df.columns:
    # nothing to match
    merged = pd.DataFrame()
else:
    # filter books for English language in details (case-insensitive) and categories containing Literature & Fiction
    def contains_lit_and_english(row):
        cat = row.get('categories') or ''
        det = row.get('details') or ''
        if not isinstance(cat, str):
            cat = str(cat)
        if not isinstance(det, str):
            det = str(det)
        return ('literature & fiction' in cat.lower()) and ('english' in det.lower())

    books_df['is_lit_and_english'] = books_df.apply(contains_lit_and_english, axis=1)
    lit_books = books_df[books_df['is_lit_and_english']]

    # merge with reviews on book_id
    merged = pd.merge(reviews, lit_books, on='book_id', how='inner')

# prepare output
output = []
if not merged.empty:
    for _, r in merged.iterrows():
        out = {
            'book_id': r.get('book_id'),
            'title': None if pd.isna(r.get('title')) else r.get('title'),
            'author': None if pd.isna(r.get('author')) else r.get('author'),
            'categories': None if pd.isna(r.get('categories')) else r.get('categories'),
            'details': None if pd.isna(r.get('details')) else r.get('details'),
            'avg_rating': float(r.get('avg_rating')) if not pd.isna(r.get('avg_rating')) else None,
            'n_reviews': int(r.get('n_reviews')) if not pd.isna(r.get('n_reviews')) else None
        }
        output.append(out)

# produce JSON string
result_str = json.dumps(output)
print("__RESULT__:")
print(result_str)"""

